### Task 9: Update GitAdapter for D69 Trait

    use corvia_kernel::chunking_fallback::FallbackChunker;
    use std::sync::Arc;

    let fallback = Arc::new(FallbackChunker::new(512));
    let mut registry = FormatRegistry::new(fallback);

    let adapter = GitAdapter::new();
    adapter.register_chunking(&mut registry);

    // After registration, .rs should resolve to "ast" not "fallback"
    let strategy = registry.resolve("rs");
    assert_eq!(strategy.name(), "ast");
}
